def verify_message_signature(data, signature, secret_key):
    """Verify HMAC signature of the message"""
    expected_signature = hmac.new(
        secret_key.encode('utf-8'),
        data,
        hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(signature, expected_signature)

